mapper.select:
SELECT dept_id, parent_id, ancestors, dept_name, dept_type, dept_category, tenant_id FROM sys_dept WHERE status = '0' AND dept_category = #{deptCategory}
AND (tenant_id = #{tenantId} OR tenant_id IS NULL)
ORDER BY tenant_id NULLS FIRST, dept_type ASC, dept_id ASC

SELECT DISTINCT tenant_id, building_id FROM c_owner_property WHERE 1 = 1
AND tenant_id = #{tenantId}
ORDER BY tenant_id ASC, building_id ASC

SELECT EXISTS(
    SELECT 1 FROM sys_user
    WHERE account_id = #{accountId}
      AND dept_id = #{deptId}
      AND status = '0'
)
